%[text] ## Section 1: 代謝物パネルの定義と記述子プロファイリング
%[text] 
%[text] ### なぜ「構造記述子」から始めるのか？
%[text] メタボロミクス（metabolomics）とは、生体試料中の多数の低分子代謝物を網羅的に測定する手法です。
%[text] 測定される代謝物はアミノ酸・有機酸・脂肪酸・糖類・腸内細菌叢産物など、化学的に非常に多様なクラスをカバーしています。
%[text] この多様性を数値で把握することで、次の 3 つの恩恵が得られます。
%[text] 1. どんな化学空間を扱っているかを視覚化できます（MW vs $\\log P$ の散布図では各クラスが分離します）。
%[text] 2. Section 3 の構造クラスタリングの準備になります（フィンガープリントは SMILES から生成します）。
%[text] 3. 変動代謝物の「なぜ」を構造的に説明する根拠になります（例: BCAA は疎水性が高く $\\log P \> 0$ → 脂質代謝と連動しやすい）。 \
%[text] 今回の 30 種パネルは Wang (2011) と Newgard (2009) の T2D メタボロミクス報告から選定しました。
%[text] SMILES は PubChem (CC0) から取得しています。
%[text] 
%[text] 代謝物パネル（30 種）の変動方向は +1 = T2D で上昇 / -1 = 低下 / 0 = 混在を表します（Wang 2011, Newgard 2009, Karlsson 2013 に基づく）。
MET_NAMES = [ ...
    "Glucose",         "Fructose",          "Mannose", ...           % 糖質 (Carbohydrates) 1/2
    "Galactose",       "Sorbitol", ...                                % 糖質 2/2
    "Isoleucine",      "Leucine",           "Valine", ...            % BCAAs
    "Phenylalanine",   "Tyrosine",          "Tryptophan", ...        % 芳香族 AAs
    "Alanine",         "Glutamine",         "Glycine", ...           % その他 AAs
    "Citric acid",     "Succinic acid",     "Fumaric acid", ...      % TCA cycle 1/2
    "Malic acid",      "Oxaloacetic acid", ...                        % TCA cycle 2/2
    "Palmitic acid",   "Oleic acid",        "Stearic acid", ...      % 脂肪酸 (Fatty Acids) 1/2
    "Arachidonic acid", ...                                           % 脂肪酸 2/2
    "Lactic acid",     "Pyruvic acid",      "3-Hydroxybutyric acid", ... % 解糖・ケトン体
    "Butyric acid",    "TMAO",              "Xanthine", ...          % 腸内細菌叢・廃棄 1/2
    "Creatinine" ...                                                  % 腸内細菌叢・廃棄 2/2
];
MET_SMILES = [ ...
    "OC[C@H]1OC(O)[C@H](O)[C@@H](O)[C@@H]1O", ...      % D-Glucose (pyranose)
    "OCC1(O)OC[C@@H](O)[C@H]1O", ...                    % D-Fructose (furanose)
    "OC[C@H]1OC(O)[C@@H](O)[C@@H](O)[C@@H]1O", ...     % D-Mannose (pyranose)
    "OC[C@H]1OC(O)[C@H](O)[C@@H](O)[C@@H]1O", ...      % D-Galactose (pyranose)
    "OC[C@H](O)[C@@H](O)[C@H](O)[C@H](O)CO", ...       % D-Sorbitol
    "CC[C@H](C)[C@@H](N)C(=O)O", ...                    % L-Isoleucine
    "CC(C)C[C@@H](N)C(=O)O", ...                        % L-Leucine
    "CC(C)[C@@H](N)C(=O)O", ...                         % L-Valine
    "N[C@@H](Cc1ccccc1)C(=O)O", ...                     % L-Phenylalanine
    "N[C@@H](Cc1ccc(O)cc1)C(=O)O", ...                  % L-Tyrosine
    "N[C@@H](Cc1c[nH]c2ccccc12)C(=O)O", ...             % L-Tryptophan
    "C[C@@H](N)C(=O)O", ...                             % L-Alanine
    "N[C@@H](CCC(N)=O)C(=O)O", ...                      % L-Glutamine
    "NCC(=O)O", ...                                      % Glycine
    "OC(CC(=O)O)(CC(=O)O)C(=O)O", ...                   % Citric acid
    "OC(=O)CCC(=O)O", ...                               % Succinic acid
    "OC(=O)/C=C/C(=O)O", ...                            % Fumaric acid (trans)
    "OC(=O)[C@H](O)CC(=O)O", ...                        % L-Malic acid
    "OC(=O)CC(=O)C(=O)O", ...                           % Oxaloacetic acid
    "CCCCCCCCCCCCCCCC(=O)O", ...                         % Palmitic acid (C16:0)
    "CCCCCCCC/C=C\CCCCCCCC(=O)O", ...                   % Oleic acid (C18:1)
    "CCCCCCCCCCCCCCCCCC(=O)O", ...                       % Stearic acid (C18:0)
    "CCCCC/C=C\C/C=C\C/C=C\C/C=C\CCCC(=O)O", ...      % Arachidonic acid (C20:4, n-6)
    "C[C@@H](O)C(=O)O", ...                             % L-Lactic acid
    "CC(=O)C(=O)O", ...                                  % Pyruvic acid
    "C[C@@H](O)CC(=O)O", ...                            % 3-Hydroxybutyric acid
    "CCCC(=O)O", ...                                     % Butyric acid (SCFA)
    "C[N+](C)(C)[O-]", ...                              % TMAO (Trimethylamine N-oxide)
    "O=C1NC(=O)c2[nH]cnc2N1", ...                       % Xanthine (2,6-dioxypurine)
    "CN1CC(=O)NC1=N" ...                                 % Creatinine
];
%[text] 経路分類（各代謝物が属するカテゴリ）を定義します。
MET_PATHWAY = [ ...
    "Carbohydrate",    "Carbohydrate",      "Carbohydrate", ...
    "Carbohydrate",    "Carbohydrate", ...
    "Amino acid",      "Amino acid",        "Amino acid", ...
    "Amino acid",      "Amino acid",        "Amino acid", ...
    "Amino acid",      "Amino acid",        "Amino acid", ...
    "TCA cycle",       "TCA cycle",         "TCA cycle", ...
    "TCA cycle",       "TCA cycle", ...
    "Lipid",           "Lipid",             "Lipid", ...
    "Lipid", ...
    "Glycolysis",      "Glycolysis",        "Ketone body", ...
    "Gut/Microbiome",  "Gut/Microbiome",    "Purine metabolism", ...
    "Waste product" ...
];
%[text] T2D における変動方向を定義します（+1 = 上昇、-1 = 低下、0 = 混在）。
MET_DIRECTION = [ ...
    +1, +1, +1, +1, +1, ...    % 糖質
    +1, +1, +1, ...             % BCAAs (Wang 2011)
    +1, +1, +1, ...             % 芳香族 AAs
     0, -1, -1, ...             % その他 AAs (Alanine:混在, Gln/Gly:低下)
    -1, -1, -1, -1, -1, ...    % TCA サイクル
    +1,  0, +1, +1, ...         % 脂肪酸 (飽和↑、MUFA:混在)
    +1, +1, +1, ...             % 解糖・ケトン体
    -1, +1, +1, +1 ...          % 腸内細菌叢 (酪酸↓, TMAO↑, Xanthine↑)
];
nMet = numel(MET_NAMES);   % = 30
%[text] SMILES 文字列から RDKit 分子オブジェクトを生成し、`emk.descriptor.batchCalculate()` で分子量（MW）、オクタノール/水分配係数（$\\log P$）、極性表面積（TPSA）などの記述子を一括計算します。
logProgress(0, nMet, "SMILES を解析して記述子を計算しています"); %[output:9ba0760c]
mols = cell(1, nMet);
for i = 1:nMet %[output:group:45d012ee]
    mols{i} = emk.mol.fromSmiles(MET_SMILES(i));
    logProgress(i, nMet, "SMILES を解析して記述子を計算しています"); %[output:65e46b12]
end %[output:group:45d012ee]
descTbl = emk.descriptor.batchCalculate(mols);
descTbl.Name      = MET_NAMES(:);
descTbl.Pathway   = MET_PATHWAY(:);
descTbl.Direction = MET_DIRECTION(:);
logInfo("R07: %d 種の代謝物について記述子を計算しました。", nMet); %[output:60e9de94]
logInfo("     MW 範囲: %.1f -- %.1f g/mol", min(descTbl.MolWt), max(descTbl.MolWt)); %[output:52dbcce0]
logInfo("     LogP 範囲: %.2f -- %.2f", min(descTbl.LogP), max(descTbl.LogP)); %[output:6eff1abc]
%[text] 経路クラスごとに色を割り当て、MW vs $\\log P$（左）および TPSA vs 水素結合ドナー数（右）の散布図で化学空間を概観します。
pathClasses = unique(MET_PATHWAY(:));
nClasses    = numel(pathClasses);
cMapMain    = lines(nClasses);
figure("Name", "R07-Fig1: Metabolite Chemical Space"); %[output:71a1696f]
tl1 = tiledlayout(1, 2, "TileSpacing", "compact"); %[output:71a1696f]
scHandles = gobjects(nClasses, 1);
nexttile; %[output:71a1696f]
hold on; %[output:71a1696f]
for ci = 1:nClasses
    idx = MET_PATHWAY == pathClasses(ci);
    scHandles(ci) = scatter(descTbl.MolWt(idx), descTbl.LogP(idx), 70, cMapMain(ci,:), ... %[output:71a1696f]
        "filled", "MarkerFaceAlpha", 0.85, "DisplayName", pathClasses(ci)); %[output:71a1696f]
end
xlabel("Molecular Weight (g/mol)"); %[output:71a1696f]
ylabel("LogP"); %[output:71a1696f]
title("Chemical Space: MW vs. LogP"); %[output:71a1696f]
hold off; %[output:71a1696f]
nexttile; %[output:71a1696f]
hold on; %[output:71a1696f]
for ci = 1:nClasses
    idx = MET_PATHWAY == pathClasses(ci);
    scatter(descTbl.TPSA(idx), descTbl.NumHDonors(idx), 70, cMapMain(ci,:), ... %[output:71a1696f]
        "filled", "MarkerFaceAlpha", 0.85, "DisplayName", pathClasses(ci)); %[output:71a1696f]
end
xlabel("TPSA (angstrom^2)"); %[output:71a1696f]
ylabel("H-Bond Donors"); %[output:71a1696f]
title("Chemical Space: TPSA vs. HBD"); %[output:71a1696f]
hold off; %[output:71a1696f]
lgd1 = legend(scHandles, pathClasses, "FontSize", 7, "NumColumns", 3); %[output:71a1696f]
lgd1.Layout.Tile = "south"; %[output:71a1696f]
logInfo("R07: Section 1 が完了しました。"); %[output:64b609e7]
%%
%[text] ## Section 2: ケースコントロール統計解析とボルケーノプロット
%[text] 
%[text] ### 非標的メタボロミクスの統計解析パイプライン
%[text] 非標的メタボロミクスの統計解析は次の流れで進みます。
%[text] 実験（LC-MS/MS）でピーク面積行列（サンプル $\\times$ 代謝物）を取得し、$\\log\_2$ 変換で正規分布に近似します。
%[text] 次に各代謝物について独立サンプル t 検定（対照 vs T2D）を行い、fold change（$\\log\_2 FC$）を計算します。
%[text] 最後に多重検定補正（FDR; Benjamini-Hochberg 法）を適用し、ボルケーノプロット（$\\log\_2 FC$ vs $-\\log\_{10} p$）を作成します。
%[text] 
%[text] ### Welch の t 検定
%[text] 2 群の平均差を検定するとき、群間で分散が等しいとは限りません。
%[text] 等分散を仮定しない Welch の t 検定では、検定統計量を次のように計算します。
%[text] $t = \\frac{\\bar{x}(1) - \\bar{x}(2)}{\\sqrt{\\frac{s(1)^2}{n(1)} + \\frac{s(2)^2}{n(2)}}}$
%[text] ここで $\\bar{x}(1),\\, \\bar{x}(2)$ はそれぞれの群の標本平均、$s(1)^2,\\, s(2)^2$ は標本分散、$n(1),\\, n(2)$ はサンプル数です。
%[text] 
%[text] ### 多重検定補正（Benjamini-Hochberg FDR）
%[text] 30 種を同時に検定すると、偶然の有意差が増える第一種誤りの蓄積が問題になります。
%[text] Benjamini-Hochberg（BH）法では p 値を昇順に並べ、$i$ 番目の p 値に補正 q 値 $q(i) = \\min\\!\\left(1,\\, p(i) \\times \\frac{m}{i}\\right)$ を割り当てます（$m$ = 検定数）。
%[text] これにより「偽陽性の期待割合（FDR）が 5% 以下」という保証が得られます。
%[text] 有意基準は $q \< 0.05$ かつ $|\\log\_2 FC| \> 0.5$（fold change $\\geq 1.41$ 倍）とします。
%[text] 
%[text] **シミュレーションデータについて**: 実験データの代わりに、文献メタアナリシスの fold change を正解値としてシミュレーションデータを生成します。
%[text] 生物学的変動係数 CV $\\approx 23\\%$（$\\log\_2$ スケールで SD = 0.3）は LC-MS/MS メタボロミクスの典型値です。
rng(42);          % 再現性のためシードを固定
nCtrl = 50;       % 対照群 n
nCase = 50;       % T2D 群 n
%[text] 各代謝物の真の $\\log\_2 FC$ を文献値に基づいて設定します。
%[text] 方向のある代謝物は $\\pm 0.55$、混在（0）の代謝物には小さいランダムノイズを与えます。
FC_MEAN = zeros(1, nMet);
for i = 1:nMet
    if MET_DIRECTION(i) ~= 0
        FC_MEAN(i) = MET_DIRECTION(i) * 0.55;
    else
        FC_MEAN(i) = 0.1 * randn();
    end
end
%[text] 各群の $\\log\_2$ 強度を正規分布でシミュレートします（平均 10、SD = 0.3）。
cvLog2   = 0.3;
ctrlData = 10 + cvLog2 * randn(nCtrl, nMet);
caseData = bsxfun(@plus, 10 + cvLog2 * randn(nCase, nMet), FC_MEAN);
%[text] Statistics Toolbox が利用できる場合は `ttest2`、ない場合は Welch t 検定を手動実装します。
pVals  = zeros(1, nMet);
log2FC = zeros(1, nMet);
for i = 1:nMet
    log2FC(i) = mean(caseData(:,i)) - mean(ctrlData(:,i));
    if hasStatsTbx
        [~, pVals(i)] = ttest2(caseData(:,i), ctrlData(:,i));
    else
        % 手動 Welch t 検定（Statistics Toolbox なしのフォールバック）
        m1 = mean(caseData(:,i));  m2 = mean(ctrlData(:,i));
        s1 = var(caseData(:,i));   s2 = var(ctrlData(:,i));
        se = sqrt(s1/nCase + s2/nCtrl);
        tStat = (m1 - m2) / se;
        df = (s1/nCase + s2/nCtrl)^2 / ...
             ((s1/nCase)^2/(nCase-1) + (s2/nCtrl)^2/(nCtrl-1));
        pVals(i) = 2 * (1 - tcdf(abs(tStat), df));
    end
end
%[text] BH 法で q 値を計算します。p 値を昇順にランク付けし、式 $q(i) = \\min(1,\\, p(i) \\times m / i)$ で補正します。
[~, sortIdx] = sort(pVals);   % sortedP is not needed; only rank order matters
m = nMet;
qVals = ones(1, nMet);
for i = 1:m
    origIdx     = sortIdx(i);
    qVals(origIdx) = min(1, pVals(origIdx) * m / i);
end
%[text] BH 法では q 値は順位に対して単調非減少である必要があるため、逆順に走査して単調性を保証します。
for i = m-1:-1:1
    qVals(sortIdx(i)) = min(qVals(sortIdx(i)), qVals(sortIdx(i+1)));
end
%[text] 有意基準（$q \< 0.05$ かつ $|\\log\_2 FC| \> 0.5$）を満たす代謝物を抽出します。
isSig = qVals < 0.05 & abs(log2FC) > 0.5;
nSig  = sum(isSig);
sigIdx = find(isSig);
[~, sortBySig] = sort(abs(log2FC(sigIdx)), "descend");
sigIdx = sigIdx(sortBySig);
logInfo("R07: 有意代謝物 %d / %d 種（q<0.05, |log2FC|>0.5）。", nSig, nMet); %[output:8bd4505e]
%[text] ボルケーノプロットは x 軸に $\\log\_2 FC$、y 軸に $-\\log\_{10} p$ を取ります。右上（T2D で上昇・有意）は赤、左上（低下・有意）は青、灰色は非有意を示します。
figure("Name", "R07-Fig2: Volcano Plot"); %[output:0dd2a02e]
hold on; %[output:0dd2a02e]
isNS = ~isSig;
isUp = isSig & log2FC >  0;
isDn = isSig & log2FC <= 0;
scatter(log2FC(isNS), -log10(pVals(isNS)), 50, [0.65 0.65 0.65], "filled", ... %[output:0dd2a02e]
    "DisplayName", sprintf("Not significant (n=%d)", sum(isNS))); %[output:0dd2a02e]
scatter(log2FC(isUp), -log10(pVals(isUp)), 80, [0.85 0.2 0.1], "filled", ... %[output:0dd2a02e]
    "DisplayName", sprintf("Upregulated in T2D (n=%d)", sum(isUp))); %[output:0dd2a02e]
scatter(log2FC(isDn), -log10(pVals(isDn)), 80, [0.1 0.3 0.85], "filled", ... %[output:0dd2a02e]
    "DisplayName", sprintf("Downregulated in T2D (n=%d)", sum(isDn))); %[output:0dd2a02e]
for i = sigIdx
    text(log2FC(i), -log10(pVals(i)) + 0.15, MET_NAMES(i), ... %[output:0dd2a02e]
        "FontSize", 7, "HorizontalAlignment", "center", "FontWeight", "bold"); %[output:0dd2a02e]
end
xline( 0.5, "--", "Color", [0.4 0.4 0.4], "HandleVisibility", "off"); %[output:0dd2a02e]
xline(-0.5, "--", "Color", [0.4 0.4 0.4], "HandleVisibility", "off"); %[output:0dd2a02e]
yline(-log10(0.05), "--r", "p_{raw} = 0.05", "HandleVisibility", "off"); %[output:0dd2a02e]
xlabel("log_2(Fold Change: T2D / Control)"); %[output:0dd2a02e]
ylabel("-log_{10}(p-value)"); %[output:0dd2a02e]
title(sprintf("Volcano Plot: T2D vs. Healthy (n=%d+%d)  [%d significant]", ... %[output:0dd2a02e]
    nCase, nCtrl, nSig)); %[output:0dd2a02e]
legend("Location", "northwest", "FontSize", 8); %[output:0dd2a02e]
hold off; %[output:0dd2a02e]
%[text] 有意代謝物のサマリーテーブルを表示します。
sigTable = table( ...
    MET_NAMES(sigIdx)', ...
    round(log2FC(sigIdx)', 3), ...
    round(qVals(sigIdx)', 4), ...
    MET_PATHWAY(sigIdx)', ...
    VariableNames=["Metabolite", "log2FC", "q_value", "Pathway"]);
logInfo("R07: 有意代謝物のサマリー:"); %[output:19054fc9]
disp(sigTable); %[output:0d8290f6]
logInfo("R07: Section 2 が完了しました。"); %[output:4f881225]
%%
%[text] ## Section 3: 構造フィンガープリントクラスタリング（A02 との接続）
%[text] 
%[text] ### なぜ変動代謝物を構造でクラスタリングするのか？
%[text] 統計的に有意な代謝物リストには、化学的に関連する分子が複数含まれます。
%[text] BCAA（Ile/Leu/Val）は脂肪族側鎖を持つアミノ酸という同じサブ構造を共有するため、同じ酵素経路（mTOR-IRS1 軸）で同時に変動する典型例です。
%[text] **Note**: シミュレーションデータ（rng=42）の確率的揺らぎにより Isoleucine が有意水準のボーダーライン付近となることがありますが、Wang (2011) の実コホートでは BCAA 3 種全てが一貫して上昇しています。
%[text] 「構造グループ」の発見が重要な理由は 3 つあります。
%[text] 1. 生物学的経路の重複仮説を強化できます（1 つの経路障害が構造類似体を同時に変動させます）。
%[text] 2. バイオマーカーパネルの「冗長性」を評価できます（同一構造クラスは情報量が重複するため、代表 1 種で代用可能です）。
%[text] 3. 標的治療薬の設計ヒントになります（構造グループ → 同一酵素 → 阻害標的の候補）。 \
%[text] A02 では 30 種の everyday chemicals で同じ手法を学びました。ここでは T2D 代謝物に適用し、化学生物学的解釈を加えます。
%[text] 
%[text] ### Morgan フィンガープリント（ECFP4）と Tanimoto 類似度
%[text] Morgan フィンガープリントは各原子周辺の「化学環境」を半径 2 ホップ（ECFP4 相当）で符号化した 2048 ビットのバイナリベクトルです。
%[text] 2 つの分子のフィンガープリントを $A$、$B$ とするとき、Tanimoto 係数は共通ビット数を和集合ビット数で割った値 $J(A, B) = \\frac{|A \\cap B|}{|A \\cup B|}$ で定義されます。
%[text] BCAA（Ile/Leu/Val）は同じサブ構造を共有するため $J$ が高く、クラスタリングで同一グループに分類されます。
%[text] Morgan フィンガープリントを全 30 代謝物に対して計算します。
logProgress(0, nMet, "Morgan フィンガープリントを計算しています"); %[output:21b2129b]
fps = cell(1, nMet);
for i = 1:nMet %[output:group:0ab673c2]
    fps{i} = emk.fingerprint.morgan(mols{i});
    logProgress(i, nMet, "Morgan フィンガープリントを計算しています"); %[output:26eb59e8]
end %[output:group:0ab673c2]
%[text] `emk.similarity.matrix()` で全代謝物ペアの Tanimoto 類似度行列（$N \\times N$ の対称行列）を計算し、距離行列（$1 - J$）に変換します。
simMat = emk.similarity.matrix(fps);   % N x N Tanimoto 対称行列
distMat = 1 - simMat;                  % Tanimoto 距離
%[text] Average リンケージ（UPGMA; 非加重対グループ平均法）で階層クラスタリングを行い、デンドログラムと有意代謝物の類似度ヒートマップを描画します。
%[text] Tanimoto 距離は非ユークリッド距離であるため、ユークリッド距離を前提とする Ward 法の代わりに UPGMA を使用します。
if hasStatsTbx %[output:group:508241a7]
    distVec = squareform(distMat, "tovector");
    Z = linkage(distVec, "average"); %[output:502aff07]
    figure("Name", "R07-Fig3: Structural Clustering"); %[output:1aec87b3]
    tiledlayout(1, 2, "TileSpacing", "compact"); %[output:1aec87b3]
    nexttile; %[output:1aec87b3]
    [~, ~, outPerm] = dendrogram(Z, nMet, ... %[output:1aec87b3]
        "Labels",          MET_NAMES, ... %[output:1aec87b3]
        "Orientation",     "right", ... %[output:1aec87b3]
        "ColorThreshold",  0.7 * max(Z(:,3))); %[output:1aec87b3]
    title("Hierarchical Clustering (UPGMA, Tanimoto dist.)"); %[output:1aec87b3]
    xlabel("Linkage Distance"); %[output:1aec87b3]
    % 有意代謝物のみの類似度ヒートマップ
    nexttile; %[output:1aec87b3]
    if nSig > 1
        smSig = simMat(sigIdx, sigIdx);
        imagesc(smSig); %[output:1aec87b3]
        colorbar; %[output:1aec87b3]
        colormap(gca, "hot"); %[output:1aec87b3]
        xticks(1:nSig); xticklabels(MET_NAMES(sigIdx)); xtickangle(45); %[output:1aec87b3]
        yticks(1:nSig); yticklabels(MET_NAMES(sigIdx)); %[output:1aec87b3]
        title("Tanimoto Similarity (Significant Metabolites)"); %[output:1aec87b3]
        clim([0, 1]); %[output:1aec87b3]
    else
        text(0.5, 0.5, "Too few significant metabolites for heatmap", ...
            "HorizontalAlignment", "center");
        axis off;
    end
else
    logWarn("R07: Statistics Toolbox が利用できないため、デンドログラムをスキップします。");
    logInfo("     ペア Tanimoto 類似度行列（%dx%d）を計算しました。", nMet, nMet);
    logInfo("     デンドログラム描画には Statistics and ML Toolbox が必要です。");
end %[output:group:508241a7]
%[text] 最も構造的に類似した有意代謝物ペアを表示します。
if nSig >= 2 %[output:group:17755b7d]
    sigSimSub = simMat(sigIdx, sigIdx);
    sigSimSub = tril(sigSimSub, -1);   % 下三角のみ（重複除外）
    [maxSim, maxLinIdx] = max(sigSimSub(:));
    [row, col] = ind2sub([nSig, nSig], maxLinIdx);
    logInfo("R07: 最も類似した有意代謝物ペア: %s <-> %s (Tanimoto = %.3f)", ... %[output:439e1a75]
        MET_NAMES(sigIdx(row)), MET_NAMES(sigIdx(col)), maxSim); %[output:439e1a75]
end %[output:group:17755b7d]
logInfo("R07: Section 3 が完了しました。"); %[output:5a013225]
%%
%[text] ## Section 4: 代謝経路アノテーションとエンリッチメント解析
%[text] 
%[text] ### 経路エンリッチメント解析とは
%[text] 有意代謝物リストが得られたら、それらがどの経路に「過剰に」含まれるかを超幾何分布検定で評価します。
%[text] 超幾何分布（hypergeometric distribution）とは、大きさ $N$ の母集団から $K$ 個の「当たり」がある場合に、$n$ 個を非復元抽出したとき $k$ 個の「当たり」を引く確率を記述する分布です。
%[text] 経路エンリッチメント解析では次の 4 変数を用います。
%[text:table]{"ignoreHeader":true}
%[text] | 変数 | 意味 | 本解析での値 |
%[text] | --- | --- | --- |
%[text] | $N$ | バックグラウンド代謝物数 | 30 |
%[text] | $K$ | その経路に属するバックグラウンド代謝物数 | 経路ごとに異なる |
%[text] | $n$ | 有意代謝物の総数 | Section 2 で決定 |
%[text] | $k$ | 有意代謝物のうちその経路に属する数 | 経路ごとに異なる |
%[text:table]
%[text] p 値は $P(X \\geq k) = 1 - F(k-1;\\, N, K, n)$ で計算します（$F$ は超幾何分布の累積分布関数）。
%[text] この値が小さいほど偶然では説明しにくく、その経路は T2D で特異的に影響を受けていると解釈します。
%[text] 
%[text] ### biopython KEGG REST API（任意）
%[text] `Bio.KEGG.REST.kegg_get()` を用いると、KEGG の BCAA 分解経路（hsa00280）の化合物リストを取得し、今回のパネルとのオーバーラップを確認できます。
PATHWAY_NAMES = unique(MET_PATHWAY(:))';   % 全経路クラス（ソート済み）
nPathways = numel(PATHWAY_NAMES);
%[text] 超幾何分布検定を各経路に対して実行します。
N = nMet;   % バックグラウンド数
n = nSig;   % 有意代謝物数
%[text] 結果ベクタを先に確保してから table に変換します（双引用符コンストラクタ問題を回避）。
enr_pathway   = strings(nPathways, 1);
enr_total     = zeros(nPathways, 1);
enr_insig     = zeros(nPathways, 1);
enr_expected  = zeros(nPathways, 1);
enr_p         = ones(nPathways, 1);
enr_or        = zeros(nPathways, 1);
for pi = 1:nPathways
    pName = PATHWAY_NAMES(pi);
    K     = sum(MET_PATHWAY == pName);                          % 経路内バックグラウンド数
    k     = sum(MET_PATHWAY(sigIdx) == pName);                  % 有意代謝物中の経路内数
    expected = n * K / N;                                        % 偶然期待値
    if K > 0 && n > 0 && hasStatsTbx
        pEnrich = 1 - hygecdf(max(k-1, 0), N, K, n);           % P(X >= k)
    elseif K > 0 && n > 0
        % フォールバック: Fisher's exact test の近似
        pEnrich = min(1, exp(gammaln(K+1) + gammaln(n+1) + ...
            gammaln(N-K+1) + gammaln(N-n+1) - gammaln(k+1) - ...
            gammaln(K-k+1) - gammaln(n-k+1) - gammaln(N-K-n+k+1) - gammaln(N+1)));
    else
        pEnrich = 1;
    end
    % オッズ比
    a = k; b = n - k; c = K - k; d = N - K - n + k;
    if b > 0 && c > 0
        oddsRatio = (a * d) / (b * c);
    else
        oddsRatio = Inf;
    end
    enr_pathway(pi)  = pName;
    enr_total(pi)    = K;
    enr_insig(pi)    = k;
    enr_expected(pi) = round(expected, 2);
    enr_p(pi)        = pEnrich;
    if b > 0 && c > 0
        enr_or(pi) = (a * d) / (b * c);
    else
        enr_or(pi) = Inf;
    end
end
enrichTbl = table(enr_pathway, enr_total, enr_insig, enr_expected, enr_p, enr_or, ...
    'VariableNames', {'Pathway','Total','InSignificant','ExpectedByChance','EnrichP','OddsRatio'});
enrichTbl = sortrows(enrichTbl, 'EnrichP', 'ascend');
logInfo("R07: 経路エンリッチメント解析が完了しました。"); %[output:27851fc3]
disp(enrichTbl); %[output:04b07acd]
%[text] biopython が利用可能な場合、KEGG REST API で BCAA 分解経路（hsa00280）の化合物リストを取得します。
if bpAvailable %[output:group:467333a9]
    logInfo("R07: KEGG hsa00280（BCAA 分解経路）を取得しています..."); %[output:3e2e851f]
    try
        kegg_rest = py.importlib.import_module("Bio.KEGG.REST");
        response  = kegg_rest.kegg_get("hsa00280");
        keggText  = string(response.read());
        logInfo("R07: KEGG hsa00280 を取得しました（%d 文字）。", strlength(keggText)); %[output:92b2854f]
        % COMPOUND エントリの行を抽出（簡易パース）
        keggLines  = splitlines(keggText);
        compFilter = startsWith(strtrim(keggLines), "COMPOUND") | ...
                     (strtrim(keggLines) ~= "" & ...
                      cellfun(@(s) ~isempty(regexp(s, '^\s+C\d{5}')), ...
                              cellstr(keggLines)));
        nComp = sum(compFilter);
        logInfo("R07: KEGG hsa00280 には約 %d 個の化合物エントリが含まれています。", nComp); %[output:66ca012e]
        logInfo("     BCAA 分解経路: Ile, Leu, Val + TCA 中間体が関与します。"); %[output:9f177a3f]
    catch ME
        logWarn("R07: KEGG REST 取得に失敗しました: %s", ME.message);
        logWarn("     組込み経路データで処理を続けます。");
    end
else
    logInfo("R07: Biopython が利用できないため、組込み経路マッピングを使用します。");
    logInfo("     KEGG REST を有効化するには: emk.setup.installExtra(""biopython"")");
end %[output:group:467333a9]
%[text] バブルチャートで経路エンリッチメントを可視化します。x 軸がオッズ比（集中度）、y 軸が $-\\log\_{10} p$（統計的有意性）、バブルサイズが有意代謝物数を示します。
figure("Name", "R07-Fig4: Pathway Enrichment Bubble Chart"); %[output:70b662e2]
validRows = isfinite(enrichTbl.OddsRatio) & enrichTbl.OddsRatio > 0;
xData  = min(enrichTbl.OddsRatio(validRows), 20);     % 表示上限 20
yData  = -log10(enrichTbl.EnrichP(validRows) + 1e-10);
szData = max(enrichTbl.InSignificant(validRows), 0.1) * 25 + 10;
bubblechart(xData, yData, szData, ... %[output:70b662e2]
    "MarkerFaceColor", [0.2 0.5 0.85], "MarkerFaceAlpha", 0.75, ... %[output:70b662e2]
    "MarkerEdgeColor", [0.1 0.3 0.6]); %[output:70b662e2]
hold on; %[output:70b662e2]
for pi = 1:sum(validRows)
    names = enrichTbl.Pathway(validRows);
    text(xData(pi) + 0.1, yData(pi), names(pi), "FontSize", 8); %[output:70b662e2]
end
yline(-log10(0.05), "--r", "p = 0.05"); %[output:70b662e2]
xlabel("Odds Ratio"); %[output:70b662e2]
ylabel("-log_{10}(Enrichment p-value)"); %[output:70b662e2]
title("Pathway Enrichment Analysis (Hypergeometric Test)"); %[output:70b662e2]
hold off; %[output:70b662e2]
logInfo("R07: Section 4 が完了しました。"); %[output:0f92abab]
%%
%[text] ## Section 5: 血糖ホメオスタシスシミュレーション（R02 との接続）
%[text] 
%[text] ### 血糖-インスリン ODE モデル（Dalla Man 2007 簡略版）
%[text] R02 では単一薬物の 1 コンパートメント PK モデルを学びました。
%[text] ここでは同じ ODE フレームワークで、より複雑なフィードバック系「血糖-インスリン-肝グルコース産生」の 3 変数モデルを構築します。
%[text] モデルの状態変数は次の 3 つです。
%[text:table]{"ignoreHeader":true}
%[text] | 変数 | 単位 | 意味 |
%[text] | --- | --- | --- |
%[text] | $G(gut)$ | mmol | 腸内グルコース（OGTT 投与分） |
%[text] | $G$ | mmol/L | 血漿グルコース濃度 |
%[text] | $I$ | pmol/L | 血漿インスリン濃度 |
%[text:table]
%[text] 3 変数の時間発展を記述する ODE（Dalla Man 2007 の簡略版）を示します。
%[text]{"align":"center"} $\\frac{dG(gut)}{dt} = -k(a) \\cdot G(gut)$
%[text]{"align":"center"} $\\frac{dG}{dt} = \\frac{k(a) \\cdot G(gut)}{V(G)} - (k(0) + k(1) \\cdot I) \\cdot G + HGP(0) \\cdot e^{-k(HGP) \\cdot I} - k(Gclr) \\cdot \\max(G - G(basal),\\, 0)$
%[text]{"align":"center"} $\\frac{dI}{dt} = \\frac{\\beta \\cdot G^2}{G^2 + K(G)^2} - k(eI) \\cdot I$
%[text] 第 1 式は腸内グルコースが速度定数 $k(a)$ で血中に吸収されることを示します。
%[text] 第 2 式の右辺は左から、腸からの流入、インスリン依存性末梢取込み（$k(1) \\cdot I$ の項）、肝グルコース産生（HGP: Hepatic Glucose Production）、腎クリアランスを表します。
%[text] 第 3 式は膵 $\\beta$ 細胞によるグルコース依存性インスリン分泌（Hill 関数）とインスリンクリアランスを記述します。
%[text] T2D 病態では $\\beta$（インスリン分泌能）が正常の 50%、$k(1)$（末梢インスリン感受性）が 50%、$HGP(0)$（肝グルコース産生）が 160% に変化します。
%[text] この 3 パラメータの変化だけで、Section 2 で観察した「グルコース上昇」を数値的に再現できます。
%[text] パラメータを設定します。
tSpan  = [0, 240];   % 4 時間 (240 分)
G0     = 5.5;        % 空腹時血漿グルコース [mmol/L]
I0     = 30;         % 空腹時インスリン [pmol/L]
Gg0    = 75 / 180 * 1000;   % OGTT 75g -> [mmol]
Vd_G   = 14;         % グルコース分布容積 [L]
ka     = 0.02;        % 腸管グルコース吸収速度定数 [/min]（胃排出 t1/2 ≈ 35 min）
k0     = 0.01;        % インスリン非依存性グルコース取込み [/min]
kHGP   = 0.005;       % 肝 HGP のインスリン感受性係数
ke_I   = 0.05;        % インスリンクリアランス速度定数 [/min]
KG     = 8.0;         % beta 細胞分泌の半飽和定数 [mmol/L]
kG_clr = 0.002;       % 高血糖時の腎クリアランス係数
G_basal = 5.5;        % 基礎血糖 [mmol/L]
%[text] 正常（Normal）と T2D それぞれのパラメータを設定します。
%[text] HGP（肝グルコース産生）は空腹時定常状態（$dG/dt = 0$）を満たすよう自動算出します。これにより T2D 条件でも基準グルコース濃度 5.5 mmol/L を初期値として整合的に使用できます。
beta_N = 5.0;   k1_N = 0.005;   % Normal: beta 細胞感度・末梢インスリン感受性
beta_T = 2.5;   k1_T = 0.0025;  % T2D: beta 50%、末梢感受性 50%
I_ss_N = beta_N * G0^2 / (ke_I * (G0^2 + KG^2));   % 正常定常インスリン [pmol/L]
HGP_N  = (k0 + k1_N * I_ss_N) * G0 / exp(-kHGP * I_ss_N);  % Normal HGP [mmol/L/min]
HGP_T  = HGP_N * 1.6;   % T2D: HGP 160%（肝インスリン抵抗性）
%[text] 無名関数（クロージャ）で ODE を定義します。`makeODE` はパラメータを束縛した ODE 関数を返します。
makeODE = @(beta, k1, HGP0) @(t, y) [ ...
    -ka * max(y(1), 0); ...
    ka * max(y(1), 0) / Vd_G ...
        - (k0 + k1 * max(y(3), 0)) * max(y(2), 0) ...
        + HGP0 * exp(-kHGP * max(y(3), 0)) ...
        - kG_clr * max(max(y(2), 0) - G_basal, 0); ...
    beta * max(y(2), 0)^2 / (max(y(2), 0)^2 + KG^2) - ke_I * max(y(3), 0) ...
];
odeNormal = makeODE(beta_N, k1_N, HGP_N);
odeT2D    = makeODE(beta_T, k1_T, HGP_T);
y0     = [Gg0; G0; I0];
tEval  = linspace(0, tSpan(2), 300);
%[text] SimBiology が利用可能な場合はコンパートメントモデルオブジェクトを生成して概念を示し、数値積分には ode45 を使用します。
if hasSimbio %[output:group:7a07f4de]
    logInfo("R07: SimBiology Toolbox を検出しました。"); %[output:8a087deb]
    logInfo("     教育的明確さのため、数値積分は ode45 を使用します。"); %[output:3ab0da68]
    logInfo("     （sbiomodel オブジェクトの生成を以下でデモします）"); %[output:54e5cbc8]
    % SimBiology モデルオブジェクトの生成（概念デモ）
    mSimbio = sbiomodel("T2D_Glucose_Homeostasis");
    cGut    = addcompartment(mSimbio, "Gut",    1.0);
    cPlasma = addcompartment(mSimbio, "Plasma", Vd_G);
    logInfo("     sbiomodel を生成しました: コンパートメント = %s, %s", ... %[output:95463052]
        cGut.Name, cPlasma.Name); %[output:95463052]
    clear mSimbio cGut cPlasma;
end %[output:group:7a07f4de]
[tN,   yN]   = ode45(odeNormal, tEval, y0);
[tT2D, yT2D] = ode45(odeT2D,   tEval, y0);
logInfo("R07: ODE シミュレーションが完了しました。"); %[output:0a295482]
%[text] OGTT（経口ブドウ糖負荷試験）シミュレーション曲線を描画します。正常（青実線）vs T2D（赤破線）を比較します。
figure("Name", "R07-Fig5: Simulated OGTT (Normal vs T2D)"); %[output:4751104c]
tiledlayout(2, 2, "TileSpacing", "compact"); %[output:4751104c]
nexttile; %[output:4751104c]
plot(tN,   yN(:,2),   "b-",  "LineWidth", 2, "DisplayName", "Normal"); %[output:4751104c]
hold on; %[output:4751104c]
plot(tT2D, yT2D(:,2), "r--", "LineWidth", 2, "DisplayName", "T2D"); %[output:4751104c]
yline(7.8,  ":k",  "IGT (7.8 mmol/L)",       "LabelVerticalAlignment", "bottom"); %[output:4751104c]
yline(11.1, "-.k", "Diabetes (11.1 mmol/L)", "LabelVerticalAlignment", "bottom"); %[output:4751104c]
xlabel("Time (min)"); ylabel("Glucose (mmol/L)"); %[output:4751104c]
title("Plasma Glucose (OGTT)"); %[output:4751104c]
legend("Location", "northeast", "FontSize", 7); %[output:4751104c]
hold off; %[output:4751104c]
nexttile; %[output:4751104c]
plot(tN,   yN(:,3),   "b-",  "LineWidth", 2, "DisplayName", "Normal"); %[output:4751104c]
hold on; %[output:4751104c]
plot(tT2D, yT2D(:,3), "r--", "LineWidth", 2, "DisplayName", "T2D"); %[output:4751104c]
xlabel("Time (min)"); ylabel("Insulin (pmol/L)"); %[output:4751104c]
title("Plasma Insulin (OGTT)"); %[output:4751104c]
legend("Location", "northeast", "FontSize", 7); %[output:4751104c]
hold off; %[output:4751104c]
nexttile; %[output:4751104c]
plot(tN,   yN(:,1),   "b-",  "LineWidth", 2, "DisplayName", "Normal"); %[output:4751104c]
hold on; %[output:4751104c]
plot(tT2D, yT2D(:,1), "r--", "LineWidth", 2, "DisplayName", "T2D"); %[output:4751104c]
xlabel("Time (min)"); ylabel("Gut Glucose (mmol)"); %[output:4751104c]
title("Gut Glucose Absorption"); %[output:4751104c]
legend("Location", "northeast", "FontSize", 7); %[output:4751104c]
hold off; %[output:4751104c]
%[text] 正常 vs T2D の定量的比較指標（$C\_{max}$、AUC）をバーグラフで示します。
nexttile; %[output:4751104c]
metrics = ["Glucose Cmax", "Insulin Cmax", "Glucose AUC (norm)"];
valNorm = [max(yN(:,2)),   max(yN(:,3)),   trapz(tN,   yN(:,2))   / 1000];
valT2D  = [max(yT2D(:,2)), max(yT2D(:,3)), trapz(tT2D, yT2D(:,2)) / 1000];
barData = [valNorm(:), valT2D(:)];
bar(barData); %[output:4751104c]
xticklabels(metrics); %[output:4751104c]
xtickangle(20); %[output:4751104c]
legend(["Normal", "T2D"], "Location", "northwest"); %[output:4751104c]
ylabel("Value (normalized units)"); %[output:4751104c]
title("PK Metric Comparison"); %[output:4751104c]
%[text] 定量的サマリーをログに出力します。
logInfo("R07: OGTT シミュレーションサマリー:"); %[output:357ef8c5]
logInfo("     Glucose Cmax: 正常 = %.2f, T2D = %.2f mmol/L (比 = %.2f 倍)", ... %[output:group:624fbd31] %[output:1a6ad54c]
    max(yN(:,2)), max(yT2D(:,2)), max(yT2D(:,2)) / max(yN(:,2))); %[output:group:624fbd31] %[output:1a6ad54c]
logInfo("     Insulin Cmax: 正常 = %.1f, T2D = %.1f pmol/L", ... %[output:group:3a2fad9d] %[output:83c678f0]
    max(yN(:,3)), max(yT2D(:,3))); %[output:group:3a2fad9d] %[output:83c678f0]
logInfo("     Glucose AUC:  正常 = %.1f, T2D = %.1f mmol/L*min (比 = %.2f 倍)", ... %[output:group:59361dd1] %[output:3d59bde8]
    trapz(tN, yN(:,2)), trapz(tT2D, yT2D(:,2)), ... %[output:3d59bde8]
    trapz(tT2D, yT2D(:,2)) / trapz(tN, yN(:,2))); %[output:group:59361dd1] %[output:3d59bde8]
logInfo("R07: T2D では Glucose AUC が正常より %.1f%% 高く、Section 2 のバイオマーカーデータと整合します。", ... %[output:group:28970ebd] %[output:1c267ce3]
    (trapz(tT2D, yT2D(:,2)) / trapz(tN, yN(:,2)) - 1) * 100); %[output:group:28970ebd] %[output:1c267ce3]
logInfo("R07: Section 5 が完了しました。"); %[output:2ac18310]
logInfo("R07: 全セクションが完了しました。Fig 1〜5 で統合的な知見を確認してください。"); %[output:014feaf2]
logInfo("     構造クラスタ（Sec 3）→ 経路エンリッチメント（Sec 4）→ ODE モデル（Sec 5）が一気通貫でつながります。"); %[output:96f84411]
%%
%[text] ## まとめ
%[text] このスクリプトでは 30 種の血漿代謝物を用いて、T2D の代謝異常を構造・統計・経路・動態の 4 層で体験しました。
%[text] - **Section 1（記述子プロファイリング）**: `emk.descriptor.batchCalculate()` で MW・$\\log P$・TPSA を一括計算し、アミノ酸・脂肪酸・TCA 代謝物が化学空間上で明確に分離することを確認しました。
%[text] - **Section 2（統計解析）**: Welch t 検定と BH 法 FDR 補正（$q \< 0.05$, $|\\log\_2 FC| \> 0.5$）により有意代謝物を同定し、BCAA・糖質の上昇と TCA 中間体の低下をボルケーノプロットで可視化しました。
%[text] - **Section 3（構造クラスタリング）**: Morgan フィンガープリント（ECFP4, 2048 bit）と UPGMA 階層クラスタリング（Tanimoto 距離に適合する手法）により有意代謝物を構造グループに分類し、糖質・飽和脂肪酸が高 Tanimoto 類似度クラスタを形成することを確認しました。
%[text] - **Section 4（経路エンリッチメント）**: 超幾何分布検定（$P(X \\geq k) = 1 - F(k-1; N, K, n)$）で有意代謝物が特定経路に過剰集中することを評価しました。パネルサイズ N=30 の制約から全経路で統計的有意差は得られませんでしたが（最小 p = 0.32）、糖質代謝経路（OR = 3.1）が最も高い集中傾向を示すことをバブルチャートで確認しました。
%[text] - **Section 5（ODE シミュレーション）**: Dalla Man (2007) の血糖-インスリン-HGP モデルで OGTT をシミュレートし、$\\beta$ 細胞機能低下・インスリン抵抗性・HGP 増加の 3 パラメータ変化だけで T2D の高血糖プロファイルが数値的に再現できることを示しました。 \

